import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I’m glad you reached out today. How are you feeling right now?"
    }
  ]);

  const [input, setInput] = useState("");

  // 🧠 Conversation memory
  const [memory, setMemory] = useState({
    topic: null,
    intensity: "low"
  });

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ---------------- GREETING ONLY ---------------- */
    if (greetings.includes(text)) {
      return "Hello. I’m here with you. Take your time — how are you feeling right now?";
    }

    /* ---------------- INTENSITY DETECTION ---------------- */
    if (
      text.includes("can't handle") ||
      text.includes("too much") ||
      text.includes("overwhelmed")
    ) {
      setMemory((prev) => ({ ...prev, intensity: "high" }));
    }

    /* ---------------- STRESS ACKNOWLEDGEMENT ---------------- */
    if (text.includes("stress") || text.includes("stressed")) {
      return "Thank you for telling me. Feeling stressed can really weigh on you. What do you feel is contributing to it right now?";
    }

    /* ---------------- TOPIC DETECTION ---------------- */
    if (text.includes("exam") || text.includes("study") || text.includes("college")) {
      setMemory({ topic: "studies", intensity: memory.intensity });
      return "It sounds like your studies are putting a lot of pressure on you. What part feels most difficult right now?";
    }

    if (text.includes("family")) {
      setMemory({ topic: "family", intensity: memory.intensity });
      return "Family pressure can be emotionally heavy. Can you share what about the situation feels most stressful?";
    }

    if (text.includes("future") || text.includes("career")) {
      setMemory({ topic: "future", intensity: memory.intensity });
      return "Uncertainty about the future can feel scary. What worries you the most when you think about it?";
    }

    /* ---------------- REFLECTIVE LISTENING ---------------- */
    if (memory.topic === "studies") {
      return "From what you’re sharing, it sounds like academic pressure has been constantly on your mind. How has this been affecting you day to day?";
    }

    if (memory.topic === "family") {
      return "It seems like you’ve been carrying a lot emotionally because of family expectations. How do you usually deal with these feelings?";
    }

    /* ---------------- HIGH INTENSITY RESPONSE ---------------- */
    if (memory.intensity === "high") {
      return "That sounds really overwhelming. I’m really glad you shared this with me. Would you like to talk more about it, or would it help to try a short calming exercise together?";
    }

    /* ---------------- BODY / SLEEP IMPACT ---------------- */
    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("focus")
    ) {
      return "When stress starts affecting your body and routine, it’s a sign you’ve been under pressure for a while. What has been hardest — sleep, focus, or motivation?";
    }

    /* ---------------- FALLBACK (HUMAN, NOT BOT) ---------------- */
    return "I’m listening. You can tell me more about whatever feels most important right now.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = { sender: "bot", text: therapistReply(input) };

    setMessages((prev) => [...prev, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type your message..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
